class Solution:
    def repeatedStringMatch(self, a: str, b: str) -> int:
        n = len(a)
        m = len(b)
        k = -(-m // n)  # ceiling division
        s = a * k
        if b in s:
            if m % n == 0:
                return k
            return k + 1
        if m % n < n - len(b):
            return -1
        return k + (m // n + 1)

